class Solution {
public:
    string resultingString(string s) {
        while (true) {
            bool changed = false;
            for (int i = 0; i < s.length() - 1; i++) {
                if (abs(s[i] - s[i + 1]) == 1 || abs(s[i] - s[i + 1]) == 25) {
                    s.erase(i, 2);
                    changed = true;
                    break;
                }
            }
            if (!changed) break;
        }
        return s;
    }
};
```

